class Solution {
public:
 vector<int> beautifulIndices(string s, string a, string b, int k) {
        vector<int> res;
        int n = s.size(), m = a.size(), o = b.size();
        vector<int> a_indices, b_indices;

        for (int i = 0; i <= n - m; ++i) if (s.substr(i, m) == a) a_indices.push_back(i);
        for (int i = 0; i <= n - o; ++i) if (s.substr(i, o) == b) b_indices.push_back(i);

        for (int i : a_indices) {
            auto it = lower_bound(b_indices.begin(), b_indices.end(), i - k);
            if (it != b_indices.end() && *it <= i + k) res.push_back(i);
        }
        return res;
    }
};
